import{i as e,r as t,s as n,t as r}from"./app-B1jqjtqq.js";var i=JSON.parse(`{"path":"/linux-tutor/awesome-shell/08-shell-scripting.html","title":"Shell 脚本编程","lang":"zh-CN","frontmatter":{"description":"Shell 脚本编程 一、脚本基础 脚本结构 创建和执行脚本 二、变量 变量定义和使用 变量命名规则 只能包含字母、数字和下划线 不能以数字开头 区分大小写（NAME 和 name 不同） 避免使用系统保留变量名 变量类型 字符串：默认类型，所有变量都是字符串 整数：通过 declare -i 声明 数组：普通数组和关联数组 只读变量：通过 reado...","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Shell 脚本编程\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-07-15T12:37:10.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"yzqdev\\",\\"url\\":\\"http://www.yzqdev.top\\"}]}"],["meta",{"property":"og:url","content":"https://yzqdev.github.io/cs-guide/cs-guide/linux-tutor/awesome-shell/08-shell-scripting.html"}],["meta",{"property":"og:site_name","content":"cs-guide"}],["meta",{"property":"og:title","content":"Shell 脚本编程"}],["meta",{"property":"og:description","content":"Shell 脚本编程 一、脚本基础 脚本结构 创建和执行脚本 二、变量 变量定义和使用 变量命名规则 只能包含字母、数字和下划线 不能以数字开头 区分大小写（NAME 和 name 不同） 避免使用系统保留变量名 变量类型 字符串：默认类型，所有变量都是字符串 整数：通过 declare -i 声明 数组：普通数组和关联数组 只读变量：通过 reado..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-07-15T12:37:10.000Z"}],["meta",{"property":"article:modified_time","content":"2026-07-15T12:37:10.000Z"}]]},"git":{"createdTime":1784119030000,"updatedTime":1784119030000,"contributors":[{"name":"yzqdev","username":"yzqdev","email":"yzqdev@outlook.com","commits":1,"url":"https://github.com/yzqdev"}]},"readingTime":{"minutes":9.88,"words":2965},"filePathRelative":"linux-tutor/awesome-shell/08-shell-scripting.md","autoDesc":true}`),a={name:`08-shell-scripting.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="shell-脚本编程" tabindex="-1"><a class="header-anchor" href="#shell-脚本编程"><span>Shell 脚本编程</span></a></h1><h2 id="一、脚本基础" tabindex="-1"><a class="header-anchor" href="#一、脚本基础"><span>一、脚本基础</span></a></h2><h3 id="脚本结构" tabindex="-1"><a class="header-anchor" href="#脚本结构"><span>脚本结构</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token comment"># -*- coding: utf-8 -*-</span></span>
<span class="line"><span class="token comment"># 脚本说明：这是一个示例脚本</span></span>
<span class="line"><span class="token comment"># 作者：Your Name</span></span>
<span class="line"><span class="token comment"># 日期：2026-07-15</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 自定义函数</span></span>
<span class="line"><span class="token keyword">function</span> <span class="token function-name function">hello</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;Hello, <span class="token variable">$1</span>!&quot;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 主函数</span></span>
<span class="line"><span class="token function-name function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    hello <span class="token string">&quot;World&quot;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 执行主函数</span></span>
<span class="line">main <span class="token string">&quot;<span class="token variable">$@</span>&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="创建和执行脚本" tabindex="-1"><a class="header-anchor" href="#创建和执行脚本"><span>创建和执行脚本</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 创建脚本</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&#39;#!/bin/bash&#39;</span> <span class="token operator">&gt;</span> script.sh</span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&#39;echo &quot;Hello World&quot;&#39;</span> <span class="token operator">&gt;&gt;</span> script.sh</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 添加执行权限</span></span>
<span class="line"><span class="token function">chmod</span> +x script.sh</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 执行方式</span></span>
<span class="line">./script.sh                          <span class="token comment"># 方式 1：需要执行权限</span></span>
<span class="line"><span class="token function">bash</span> script.sh                       <span class="token comment"># 方式 2：作为参数传给 bash</span></span>
<span class="line"><span class="token builtin class-name">source</span> script.sh                     <span class="token comment"># 方式 3：在当前 Shell 执行（不创建子进程）</span></span>
<span class="line"><span class="token builtin class-name">.</span> script.sh                          <span class="token comment"># 方式 4：同 source（. 是 source 的简写）</span></span>
<span class="line"></span></code></pre></div><hr><h2 id="二、变量" tabindex="-1"><a class="header-anchor" href="#二、变量"><span>二、变量</span></a></h2><h3 id="变量定义和使用" tabindex="-1"><a class="header-anchor" href="#变量定义和使用"><span>变量定义和使用</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 变量定义（= 两边不能有空格）</span></span>
<span class="line"><span class="token assign-left variable">name</span><span class="token operator">=</span><span class="token string">&quot;John&quot;</span></span>
<span class="line"><span class="token assign-left variable">age</span><span class="token operator">=</span><span class="token number">25</span></span>
<span class="line"><span class="token assign-left variable">PI</span><span class="token operator">=</span><span class="token number">3.14159</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 使用变量</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">$name</span>                           <span class="token comment"># 输出：John</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${name}</span>                         <span class="token comment"># 推荐写法（花括号明确边界）</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;My name is <span class="token variable">$name</span>&quot;</span>              <span class="token comment"># 双引号中会解析变量</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&#39;My name is $name&#39;</span>              <span class="token comment"># 单引号中不会解析变量（输出：$name）</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 只读变量</span></span>
<span class="line"><span class="token builtin class-name">readonly</span> <span class="token assign-left variable">PI</span><span class="token operator">=</span><span class="token number">3.14159</span></span>
<span class="line"><span class="token comment"># PI=3.14  # 会报错：readonly variable</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 删除变量</span></span>
<span class="line"><span class="token builtin class-name">unset</span> name                           <span class="token comment"># 删除变量（不能删除 readonly 变量）</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="变量命名规则" tabindex="-1"><a class="header-anchor" href="#变量命名规则"><span>变量命名规则</span></a></h3><ul><li>只能包含字母、数字和下划线</li><li>不能以数字开头</li><li>区分大小写（<code>NAME</code> 和 <code>name</code> 不同）</li><li>避免使用系统保留变量名</li></ul><h3 id="变量类型" tabindex="-1"><a class="header-anchor" href="#变量类型"><span>变量类型</span></a></h3><ul><li><strong>字符串</strong>：默认类型，所有变量都是字符串</li><li><strong>整数</strong>：通过 <code>declare -i</code> 声明</li><li><strong>数组</strong>：普通数组和关联数组</li><li><strong>只读变量</strong>：通过 <code>readonly</code> 声明</li><li><strong>环境变量</strong>：通过 <code>export</code> 导出</li></ul><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 整数变量</span></span>
<span class="line"><span class="token builtin class-name">declare</span> <span class="token parameter variable">-i</span> <span class="token assign-left variable">num</span><span class="token operator">=</span><span class="token number">10</span></span>
<span class="line"><span class="token assign-left variable">num</span><span class="token operator">=</span>num+5                            <span class="token comment"># 自动算术运算</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">$num</span>                            <span class="token comment"># 输出：15</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 环境变量</span></span>
<span class="line"><span class="token builtin class-name">export</span> <span class="token assign-left variable">MY_VAR</span><span class="token operator">=</span><span class="token string">&quot;hello&quot;</span>                <span class="token comment"># 导出为环境变量（子进程可访问）</span></span>
<span class="line"></span></code></pre></div><h3 id="特殊变量" tabindex="-1"><a class="header-anchor" href="#特殊变量"><span>特殊变量</span></a></h3><table><thead><tr><th>变量</th><th>说明</th></tr></thead><tbody><tr><td><code>$0</code></td><td>脚本名称</td></tr><tr><td><code>$1</code> ~ <code>$9</code></td><td>第 1 到第 9 个位置参数</td></tr><tr><td><code>$10</code></td><td>第 10 个位置参数（需用 <code>\${10}</code>）</td></tr><tr><td><code>$#</code></td><td>位置参数个数</td></tr><tr><td><code>$*</code></td><td>所有参数（作为一个字符串）</td></tr><tr><td><code>$@</code></td><td>所有参数（作为多个字符串）</td></tr><tr><td><code>$?</code></td><td>上一条命令的退出状态码（0 成功，非 0 失败）</td></tr><tr><td><code>$$</code></td><td>当前脚本的 PID</td></tr><tr><td><code>$!</code></td><td>最后一个后台进程的 PID</td></tr><tr><td><code>$-</code></td><td>当前 Shell 的选项标志</td></tr><tr><td><code>$_</code></td><td>上一个命令的最后一个参数</td></tr></tbody></table><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;脚本名: <span class="token variable">$0</span>&quot;</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;参数个数: <span class="token variable">$#</span>&quot;</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;所有参数: <span class="token variable">$*</span>&quot;</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;所有参数: <span class="token variable">$@</span>&quot;</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;第一个参数: <span class="token variable">$1</span>&quot;</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;第二个参数: <span class="token variable">$2</span>&quot;</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;脚本 PID: <span class="token variable">$$</span>&quot;</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;退出状态码: <span class="token variable">$?</span>&quot;</span></span>
<span class="line"></span></code></pre></div><h3 id="位置参数操作" tabindex="-1"><a class="header-anchor" href="#位置参数操作"><span>位置参数操作</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token builtin class-name">shift</span>                                <span class="token comment"># 左移参数（$2 变成 $1）</span></span>
<span class="line"><span class="token builtin class-name">shift</span> <span class="token number">2</span>                              <span class="token comment"># 左移 2 个位置</span></span>
<span class="line"><span class="token builtin class-name">set</span> -- arg1 arg2 arg3                <span class="token comment"># 重新设置位置参数</span></span>
<span class="line"></span></code></pre></div><h3 id="默认值" tabindex="-1"><a class="header-anchor" href="#默认值"><span>默认值</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 变量替换</span></span>
<span class="line"><span class="token variable">\${var<span class="token operator">:-</span>default}</span>                      <span class="token comment"># 如果 var 未设置或为空，使用 default</span></span>
<span class="line"><span class="token variable">\${var<span class="token operator">:=</span>default}</span>                      <span class="token comment"># 如果 var 未设置或为空，赋值为 default</span></span>
<span class="line"><span class="token variable">\${var<span class="token operator">:?</span>error_msg}</span>                    <span class="token comment"># 如果 var 未设置或为空，输出错误</span></span>
<span class="line"><span class="token variable">\${var<span class="token operator">:+</span>replacement}</span>                  <span class="token comment"># 如果 var 已设置，使用 replacement</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 示例</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${name<span class="token operator">:-</span>&quot;World&quot;}</span>                <span class="token comment"># 如果 name 未设置，输出 &quot;World&quot;</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${name<span class="token operator">:=</span>&quot;John&quot;}</span>                 <span class="token comment"># 如果 name 未设置，设置为 &quot;John&quot;</span></span>
<span class="line"><span class="token builtin class-name">:</span> <span class="token variable">\${name<span class="token operator">:=</span>&quot;John&quot;}</span>                    <span class="token comment"># 安全的赋值方式（不输出）</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${name<span class="token operator">:?</span>&quot;name is required&quot;}</span>     <span class="token comment"># 如果未设置，输出错误</span></span>
<span class="line"></span></code></pre></div><h3 id="字符串操作" tabindex="-1"><a class="header-anchor" href="#字符串操作"><span>字符串操作</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token assign-left variable">str</span><span class="token operator">=</span><span class="token string">&quot;Hello World&quot;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 长度</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${<span class="token operator">#</span>str}</span>                         <span class="token comment"># 输出：11</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 截取</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${str<span class="token operator">:</span>0<span class="token operator">:</span>5}</span>                      <span class="token comment"># 输出：Hello（从 0 开始取 5 个字符）</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${str<span class="token operator">:</span>6}</span>                        <span class="token comment"># 输出：World（从 6 开始到末尾）</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${str<span class="token operator">:</span> -5}</span>                      <span class="token comment"># 输出：World（从末尾取 5 个）</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 删除匹配</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${str<span class="token operator">#</span>He*}</span>                       <span class="token comment"># 删除最短匹配前缀：llo World</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${str<span class="token operator">##</span>H*o}</span>                      <span class="token comment"># 删除最长匹配前缀：rld</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${str<span class="token operator">%</span>W*d}</span>                      <span class="token comment"># 删除最短匹配后缀：Hello</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${str<span class="token operator">%%</span>W*d}</span>                     <span class="token comment"># 删除最长匹配后缀：Hello</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 替换</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${str<span class="token operator">/</span>World<span class="token operator">/</span>Linux}</span>              <span class="token comment"># 替换第一个匹配：Hello Linux</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${str<span class="token operator">/</span><span class="token operator">/</span>l<span class="token operator">/</span>L}</span>                     <span class="token comment"># 替换所有匹配：HeLLo WorLd</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${str<span class="token operator">/</span><span class="token operator">#</span>Hello<span class="token operator">/</span>Hi}</span>                <span class="token comment"># 替换开头匹配：Hi World</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${str<span class="token operator">/</span><span class="token operator">%</span>World<span class="token operator">/</span>Everyone}</span>          <span class="token comment"># 替换结尾匹配：Hello Everyone</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 大小写转换</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${str<span class="token operator">,,</span>}</span>                        <span class="token comment"># 全部小写：hello world</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${str<span class="token operator">^^</span>}</span>                        <span class="token comment"># 全部大写：HELLO WORLD</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${str<span class="token operator">,</span>}</span>                         <span class="token comment"># 首字母小写：hello World</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${str<span class="token operator">^</span>}</span>                         <span class="token comment"># 首字母大写：Hello World</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 判断变量是否存在</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${str<span class="token operator">:+</span>exists}</span>                  <span class="token comment"># 存在则输出 &quot;exists&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="数组" tabindex="-1"><a class="header-anchor" href="#数组"><span>数组</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 普通数组（索引数组）</span></span>
<span class="line"><span class="token assign-left variable">arr</span><span class="token operator">=</span><span class="token punctuation">(</span><span class="token string">&quot;apple&quot;</span> <span class="token string">&quot;banana&quot;</span> <span class="token string">&quot;cherry&quot;</span><span class="token punctuation">)</span>      <span class="token comment"># 定义数组</span></span>
<span class="line">arr<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token operator">=</span><span class="token string">&quot;apple&quot;</span>                       <span class="token comment"># 逐个赋值</span></span>
<span class="line"><span class="token assign-left variable">arr</span><span class="token operator">+=</span><span class="token string">&quot;date&quot;</span>                          <span class="token comment"># 追加元素</span></span>
<span class="line"></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${arr<span class="token punctuation">[</span>0<span class="token punctuation">]</span>}</span>                       <span class="token comment"># 输出第一个元素：apple</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${arr<span class="token punctuation">[</span>-1<span class="token punctuation">]</span>}</span>                      <span class="token comment"># 输出最后一个元素：cherry</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${arr<span class="token punctuation">[</span>@<span class="token punctuation">]</span>}</span>                       <span class="token comment"># 输出所有元素</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${arr<span class="token punctuation">[</span>*<span class="token punctuation">]</span>}</span>                       <span class="token comment"># 输出所有元素</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${<span class="token operator">#</span>arr<span class="token punctuation">[</span>@<span class="token punctuation">]</span>}</span>                      <span class="token comment"># 数组长度</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${<span class="token operator">!</span>arr<span class="token punctuation">[</span>@<span class="token punctuation">]</span>}</span>                      <span class="token comment"># 所有索引</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 遍历数组</span></span>
<span class="line"><span class="token keyword">for</span> <span class="token for-or-select variable">i</span> <span class="token keyword">in</span> <span class="token string">&quot;<span class="token variable">\${arr<span class="token punctuation">[</span>@<span class="token punctuation">]</span>}</span>&quot;</span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;<span class="token variable">$i</span>&quot;</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 关联数组（需要 Bash 4+）</span></span>
<span class="line"><span class="token builtin class-name">declare</span> <span class="token parameter variable">-A</span> map</span>
<span class="line">map<span class="token punctuation">[</span><span class="token string">&quot;name&quot;</span><span class="token punctuation">]</span><span class="token operator">=</span><span class="token string">&quot;John&quot;</span></span>
<span class="line">map<span class="token punctuation">[</span><span class="token string">&quot;age&quot;</span><span class="token punctuation">]</span><span class="token operator">=</span><span class="token number">25</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${map<span class="token punctuation">[</span>&quot;name&quot;<span class="token punctuation">]</span>}</span>                  <span class="token comment"># 输出：John</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${<span class="token operator">!</span>map<span class="token punctuation">[</span>@<span class="token punctuation">]</span>}</span>                      <span class="token comment"># 输出所有键</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">\${map<span class="token punctuation">[</span>@<span class="token punctuation">]</span>}</span>                       <span class="token comment"># 输出所有值</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="三、算术运算" tabindex="-1"><a class="header-anchor" href="#三、算术运算"><span>三、算术运算</span></a></h2><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 方法 1：$((...))</span></span>
<span class="line"><span class="token assign-left variable">a</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$((</span><span class="token number">1</span> <span class="token operator">+</span> <span class="token number">2</span><span class="token variable">))</span></span></span>
<span class="line"><span class="token assign-left variable">b</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$((</span>a <span class="token operator">*</span> <span class="token number">3</span><span class="token variable">))</span></span></span>
<span class="line"><span class="token assign-left variable">c</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$((</span><span class="token number">2</span> <span class="token operator">**</span> <span class="token number">10</span><span class="token variable">))</span></span>                       <span class="token comment"># 2 的 10 次方</span></span>
<span class="line"><span class="token assign-left variable">d</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$((</span> <span class="token punctuation">(</span>a <span class="token operator">+</span> b<span class="token punctuation">)</span> <span class="token operator">*</span> <span class="token number">2</span> <span class="token variable">))</span></span></span>
<span class="line"><span class="token assign-left variable">e</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$((</span>a <span class="token operator">&gt;</span> b <span class="token operator">?</span> a <span class="token operator">:</span> b<span class="token variable">))</span></span>                 <span class="token comment"># 三目运算符</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 方法 2：let</span></span>
<span class="line"><span class="token builtin class-name">let</span> <span class="token assign-left variable">a</span><span class="token operator">=</span><span class="token number">1</span>+2</span>
<span class="line"><span class="token builtin class-name">let</span> <span class="token assign-left variable">a</span><span class="token operator">+=</span><span class="token number">5</span></span>
<span class="line"><span class="token builtin class-name">let</span> a*<span class="token operator">=</span><span class="token number">2</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 方法 3：expr</span></span>
<span class="line"><span class="token assign-left variable">a</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$(</span><span class="token function">expr</span> <span class="token number">1</span> + <span class="token number">2</span><span class="token variable">)</span></span>                      <span class="token comment"># 注意：运算符两边必须有空格</span></span>
<span class="line"><span class="token comment"># 方法 4：bc（浮点数）</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;scale=2; 10 / 3&quot;</span> <span class="token operator">|</span> <span class="token function">bc</span>          <span class="token comment"># 输出：3.33</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;sqrt(100)&quot;</span> <span class="token operator">|</span> <span class="token function">bc</span>                <span class="token comment"># 输出：10</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;2^10&quot;</span> <span class="token operator">|</span> <span class="token function">bc</span>                     <span class="token comment"># 输出：1024</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 操作符</span></span>
<span class="line"><span class="token comment"># +, -, *, /, %, **（幂运算）</span></span>
<span class="line"><span class="token comment"># +=, -=, *=, /=, %= （赋值运算）</span></span>
<span class="line"><span class="token comment"># ++, -- （递增递减）</span></span>
<span class="line"><span class="token comment"># 注意：* 在 $((...)) 中不需要转义</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="四、条件判断" tabindex="-1"><a class="header-anchor" href="#四、条件判断"><span>四、条件判断</span></a></h2><h3 id="test-命令和" tabindex="-1"><a class="header-anchor" href="#test-命令和"><span><code>test</code> 命令和 <code>[ ]</code></span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 文件测试</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token parameter variable">-f</span> <span class="token string">&quot;<span class="token variable">$file</span>&quot;</span> <span class="token punctuation">]</span>                       <span class="token comment"># 是否为普通文件</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token parameter variable">-d</span> <span class="token string">&quot;<span class="token variable">$dir</span>&quot;</span> <span class="token punctuation">]</span>                        <span class="token comment"># 是否为目录</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token parameter variable">-e</span> <span class="token string">&quot;<span class="token variable">$path</span>&quot;</span> <span class="token punctuation">]</span>                       <span class="token comment"># 是否存在</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token parameter variable">-s</span> <span class="token string">&quot;<span class="token variable">$file</span>&quot;</span> <span class="token punctuation">]</span>                       <span class="token comment"># 文件大小 &gt; 0</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token parameter variable">-r</span> <span class="token string">&quot;<span class="token variable">$file</span>&quot;</span> <span class="token punctuation">]</span>                       <span class="token comment"># 是否可读</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token parameter variable">-w</span> <span class="token string">&quot;<span class="token variable">$file</span>&quot;</span> <span class="token punctuation">]</span>                       <span class="token comment"># 是否可写</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token parameter variable">-x</span> <span class="token string">&quot;<span class="token variable">$file</span>&quot;</span> <span class="token punctuation">]</span>                       <span class="token comment"># 是否可执行</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token parameter variable">-L</span> <span class="token string">&quot;<span class="token variable">$file</span>&quot;</span> <span class="token punctuation">]</span>                       <span class="token comment"># 是否为符号链接</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token parameter variable">-c</span> <span class="token string">&quot;<span class="token variable">$file</span>&quot;</span> <span class="token punctuation">]</span>                       <span class="token comment"># 是否为字符设备</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token parameter variable">-b</span> <span class="token string">&quot;<span class="token variable">$file</span>&quot;</span> <span class="token punctuation">]</span>                       <span class="token comment"># 是否为块设备</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token parameter variable">-N</span> <span class="token string">&quot;<span class="token variable">$file</span>&quot;</span> <span class="token punctuation">]</span>                       <span class="token comment"># 文件是否上次读取后被修改过</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token parameter variable">-O</span> <span class="token string">&quot;<span class="token variable">$file</span>&quot;</span> <span class="token punctuation">]</span>                       <span class="token comment"># 是否当前用户所有</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token parameter variable">-G</span> <span class="token string">&quot;<span class="token variable">$file</span>&quot;</span> <span class="token punctuation">]</span>                       <span class="token comment"># 是否当前用户组所有</span></span>
<span class="line"><span class="token punctuation">[</span> file1 <span class="token parameter variable">-nt</span> file2 <span class="token punctuation">]</span>                  <span class="token comment"># file1 是否比 file2 新</span></span>
<span class="line"><span class="token punctuation">[</span> file1 <span class="token parameter variable">-ot</span> file2 <span class="token punctuation">]</span>                  <span class="token comment"># file1 是否比 file2 旧</span></span>
<span class="line"><span class="token punctuation">[</span> file1 <span class="token parameter variable">-ef</span> file2 <span class="token punctuation">]</span>                  <span class="token comment"># 是否指向同一个 inode</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 字符串测试</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token parameter variable">-z</span> <span class="token string">&quot;<span class="token variable">$str</span>&quot;</span> <span class="token punctuation">]</span>                        <span class="token comment"># 字符串是否为空（长度 0）</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token parameter variable">-n</span> <span class="token string">&quot;<span class="token variable">$str</span>&quot;</span> <span class="token punctuation">]</span>                        <span class="token comment"># 字符串是否非空</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$str1</span>&quot;</span> <span class="token operator">=</span> <span class="token string">&quot;<span class="token variable">$str2</span>&quot;</span> <span class="token punctuation">]</span>               <span class="token comment"># 字符串是否相等</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$str1</span>&quot;</span> <span class="token operator">==</span> <span class="token string">&quot;<span class="token variable">$str2</span>&quot;</span> <span class="token punctuation">]</span>              <span class="token comment"># 同上（bash 扩展）</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$str1</span>&quot;</span> <span class="token operator">!=</span> <span class="token string">&quot;<span class="token variable">$str2</span>&quot;</span> <span class="token punctuation">]</span>              <span class="token comment"># 字符串是否不等</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$str1</span>&quot;</span> <span class="token operator">&lt;</span> <span class="token string">&quot;<span class="token variable">$str2</span>&quot;</span> <span class="token punctuation">]</span>               <span class="token comment"># 字典序小于</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$str1</span>&quot;</span> <span class="token operator">&gt;</span> <span class="token string">&quot;<span class="token variable">$str2</span>&quot;</span> <span class="token punctuation">]</span>               <span class="token comment"># 字典序大于</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 整数比较</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$a</span>&quot;</span> <span class="token parameter variable">-eq</span> <span class="token string">&quot;<span class="token variable">$b</span>&quot;</span> <span class="token punctuation">]</span>                    <span class="token comment"># 等于</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$a</span>&quot;</span> <span class="token parameter variable">-ne</span> <span class="token string">&quot;<span class="token variable">$b</span>&quot;</span> <span class="token punctuation">]</span>                    <span class="token comment"># 不等于</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$a</span>&quot;</span> <span class="token parameter variable">-gt</span> <span class="token string">&quot;<span class="token variable">$b</span>&quot;</span> <span class="token punctuation">]</span>                    <span class="token comment"># 大于</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$a</span>&quot;</span> <span class="token parameter variable">-ge</span> <span class="token string">&quot;<span class="token variable">$b</span>&quot;</span> <span class="token punctuation">]</span>                    <span class="token comment"># 大于等于</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$a</span>&quot;</span> <span class="token parameter variable">-lt</span> <span class="token string">&quot;<span class="token variable">$b</span>&quot;</span> <span class="token punctuation">]</span>                    <span class="token comment"># 小于</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$a</span>&quot;</span> <span class="token parameter variable">-le</span> <span class="token string">&quot;<span class="token variable">$b</span>&quot;</span> <span class="token punctuation">]</span>                    <span class="token comment"># 小于等于</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 逻辑运算符</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$a</span>&quot;</span> <span class="token parameter variable">-gt</span> <span class="token number">0</span> <span class="token parameter variable">-a</span> <span class="token string">&quot;<span class="token variable">$a</span>&quot;</span> <span class="token parameter variable">-lt</span> <span class="token number">10</span> <span class="token punctuation">]</span>       <span class="token comment"># 与（-a）</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$a</span>&quot;</span> <span class="token parameter variable">-gt</span> <span class="token number">0</span> <span class="token parameter variable">-o</span> <span class="token string">&quot;<span class="token variable">$a</span>&quot;</span> <span class="token parameter variable">-lt</span> <span class="token parameter variable">-10</span> <span class="token punctuation">]</span>      <span class="token comment"># 或（-o）</span></span>
<span class="line"><span class="token punctuation">[</span> <span class="token operator">!</span> <span class="token string">&quot;<span class="token variable">$a</span>&quot;</span> <span class="token parameter variable">-gt</span> <span class="token number">0</span> <span class="token punctuation">]</span>                     <span class="token comment"># 非（!）</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="—-改进的条件测试-推荐" tabindex="-1"><a class="header-anchor" href="#—-改进的条件测试-推荐"><span><code>[[ ]]</code> — 改进的条件测试（推荐）</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 支持正则</span></span>
<span class="line"><span class="token punctuation">[</span><span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$str</span>&quot;</span> <span class="token operator">=~</span> ^<span class="token punctuation">[</span><span class="token number">0</span>-9<span class="token punctuation">]</span>+$ <span class="token punctuation">]</span><span class="token punctuation">]</span>            <span class="token comment"># 匹配正则：是否全为数字</span></span>
<span class="line"><span class="token punctuation">[</span><span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$str</span>&quot;</span> <span class="token operator">=~</span> ^<span class="token punctuation">[</span>a-zA-Z<span class="token punctuation">]</span>+$ <span class="token punctuation">]</span><span class="token punctuation">]</span>         <span class="token comment"># 匹配正则：是否全为字母</span></span>
<span class="line"><span class="token punctuation">[</span><span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$str</span>&quot;</span> <span class="token operator">=~</span> ^<span class="token punctuation">[</span><span class="token number">0</span>-9<span class="token punctuation">]</span><span class="token punctuation">{</span><span class="token number">3,5</span><span class="token punctuation">}</span>$ <span class="token punctuation">]</span><span class="token punctuation">]</span>        <span class="token comment"># 3-5 位数字</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 模式匹配</span></span>
<span class="line"><span class="token punctuation">[</span><span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$str</span>&quot;</span> <span class="token operator">==</span> *.txt <span class="token punctuation">]</span><span class="token punctuation">]</span>               <span class="token comment"># 是否为 .txt 结尾</span></span>
<span class="line"><span class="token punctuation">[</span><span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$str</span>&quot;</span> <span class="token operator">==</span> <span class="token punctuation">[</span>a-z<span class="token punctuation">]</span>* <span class="token punctuation">]</span><span class="token punctuation">]</span>              <span class="token comment"># 是否以小写字母开头</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 逻辑运算符（更直观）</span></span>
<span class="line"><span class="token punctuation">[</span><span class="token punctuation">[</span> <span class="token variable">$a</span> <span class="token parameter variable">-gt</span> <span class="token number">0</span> <span class="token operator">&amp;&amp;</span> <span class="token variable">$a</span> <span class="token parameter variable">-lt</span> <span class="token number">10</span> <span class="token punctuation">]</span><span class="token punctuation">]</span>         <span class="token comment"># 与（&amp;&amp;）</span></span>
<span class="line"><span class="token punctuation">[</span><span class="token punctuation">[</span> <span class="token variable">$a</span> <span class="token parameter variable">-gt</span> <span class="token number">0</span> <span class="token operator">||</span> <span class="token variable">$a</span> <span class="token parameter variable">-lt</span> <span class="token parameter variable">-10</span> <span class="token punctuation">]</span><span class="token punctuation">]</span>        <span class="token comment"># 或（||）</span></span>
<span class="line"><span class="token punctuation">[</span><span class="token punctuation">[</span> <span class="token operator">!</span> <span class="token variable">$a</span> <span class="token parameter variable">-gt</span> <span class="token number">0</span> <span class="token punctuation">]</span><span class="token punctuation">]</span>                     <span class="token comment"># 非（!）</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 在 [[ ]] 中，变量不需要加引号（安全）</span></span>
<span class="line"><span class="token punctuation">[</span><span class="token punctuation">[</span> <span class="token variable">$a</span> <span class="token operator">&gt;</span> <span class="token number">0</span> <span class="token punctuation">]</span><span class="token punctuation">]</span>                         <span class="token comment"># 可以直接使用 &gt; &lt;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="if-语句" tabindex="-1"><a class="header-anchor" href="#if-语句"><span><code>if</code> 语句</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 基本语法</span></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">[</span> condition <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">    commands</span>
<span class="line"><span class="token keyword">fi</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># if-else</span></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">[</span> condition <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">    commands</span>
<span class="line"><span class="token keyword">else</span></span>
<span class="line">    commands</span>
<span class="line"><span class="token keyword">fi</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># if-elif-else</span></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">[</span> condition1 <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">    commands1</span>
<span class="line"><span class="token keyword">elif</span> <span class="token punctuation">[</span> condition2 <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">    commands2</span>
<span class="line"><span class="token keyword">else</span></span>
<span class="line">    commands3</span>
<span class="line"><span class="token keyword">fi</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 示例</span></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token parameter variable">-f</span> <span class="token string">&quot;<span class="token variable">$file</span>&quot;</span> <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;<span class="token variable">$file</span> 存在&quot;</span></span>
<span class="line"><span class="token keyword">elif</span> <span class="token punctuation">[</span> <span class="token parameter variable">-d</span> <span class="token string">&quot;<span class="token variable">$file</span>&quot;</span> <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;<span class="token variable">$file</span> 是目录&quot;</span></span>
<span class="line"><span class="token keyword">else</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;<span class="token variable">$file</span> 不存在&quot;</span></span>
<span class="line"><span class="token keyword">fi</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 一行写法</span></span>
<span class="line"><span class="token punctuation">[</span><span class="token punctuation">[</span> <span class="token variable">$a</span> <span class="token parameter variable">-gt</span> <span class="token number">0</span> <span class="token punctuation">]</span><span class="token punctuation">]</span> <span class="token operator">&amp;&amp;</span> <span class="token builtin class-name">echo</span> <span class="token string">&quot;positive&quot;</span>    <span class="token comment"># 如果条件为真，执行</span></span>
<span class="line"><span class="token punctuation">[</span><span class="token punctuation">[</span> <span class="token variable">$a</span> <span class="token parameter variable">-gt</span> <span class="token number">0</span> <span class="token punctuation">]</span><span class="token punctuation">]</span> <span class="token operator">||</span> <span class="token builtin class-name">echo</span> <span class="token string">&quot;not positive&quot;</span> <span class="token comment"># 如果条件为假，执行</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="case-语句" tabindex="-1"><a class="header-anchor" href="#case-语句"><span><code>case</code> 语句</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token keyword">case</span> <span class="token variable">$var</span> <span class="token keyword">in</span></span>
<span class="line">    pattern1<span class="token punctuation">)</span></span>
<span class="line">        commands1</span>
<span class="line">        <span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line">    pattern2<span class="token operator">|</span>pattern3<span class="token punctuation">)</span></span>
<span class="line">        commands2</span>
<span class="line">        <span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">[</span><span class="token number">0</span>-9<span class="token punctuation">]</span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token builtin class-name">echo</span> <span class="token string">&quot;单个数字&quot;</span></span>
<span class="line">        <span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line">    *<span class="token punctuation">)</span></span>
<span class="line">        <span class="token builtin class-name">echo</span> <span class="token string">&quot;默认情况&quot;</span></span>
<span class="line">        <span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">esac</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 示例</span></span>
<span class="line"><span class="token keyword">case</span> <span class="token variable">$1</span> <span class="token keyword">in</span></span>
<span class="line">    start<span class="token operator">|</span>s<span class="token punctuation">)</span></span>
<span class="line">        systemctl start nginx</span>
<span class="line">        <span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line">    stop<span class="token operator">|</span>t<span class="token punctuation">)</span></span>
<span class="line">        systemctl stop nginx</span>
<span class="line">        <span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line">    restart<span class="token operator">|</span>r<span class="token punctuation">)</span></span>
<span class="line">        systemctl restart nginx</span>
<span class="line">        <span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line">    status<span class="token operator">|</span>st<span class="token punctuation">)</span></span>
<span class="line">        systemctl status nginx</span>
<span class="line">        <span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line">    *<span class="token punctuation">)</span></span>
<span class="line">        <span class="token builtin class-name">echo</span> <span class="token string">&quot;Usage: <span class="token variable">$0</span> {start|stop|restart|status}&quot;</span></span>
<span class="line">        <span class="token builtin class-name">exit</span> <span class="token number">1</span></span>
<span class="line">        <span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">esac</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="五、循环" tabindex="-1"><a class="header-anchor" href="#五、循环"><span>五、循环</span></a></h2><h3 id="for-循环" tabindex="-1"><a class="header-anchor" href="#for-循环"><span><code>for</code> 循环</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 遍历列表</span></span>
<span class="line"><span class="token keyword">for</span> <span class="token for-or-select variable">i</span> <span class="token keyword">in</span> <span class="token number">1</span> <span class="token number">2</span> <span class="token number">3</span> <span class="token number">4</span> <span class="token number">5</span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token variable">$i</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 遍历数组</span></span>
<span class="line"><span class="token assign-left variable">arr</span><span class="token operator">=</span><span class="token punctuation">(</span><span class="token string">&quot;apple&quot;</span> <span class="token string">&quot;banana&quot;</span> <span class="token string">&quot;cherry&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">for</span> <span class="token for-or-select variable">fruit</span> <span class="token keyword">in</span> <span class="token string">&quot;<span class="token variable">\${arr<span class="token punctuation">[</span>@<span class="token punctuation">]</span>}</span>&quot;</span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token variable">$fruit</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># C 风格</span></span>
<span class="line"><span class="token keyword">for</span> <span class="token variable"><span class="token punctuation">((</span>i<span class="token operator">=</span><span class="token number">0</span><span class="token punctuation">;</span> i<span class="token operator">&lt;</span><span class="token number">10</span><span class="token punctuation">;</span> i<span class="token operator">++</span><span class="token punctuation">))</span></span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token variable">$i</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 遍历文件</span></span>
<span class="line"><span class="token keyword">for</span> <span class="token for-or-select variable">file</span> <span class="token keyword">in</span> *.txt<span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;处理文件: <span class="token variable">$file</span>&quot;</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 遍历命令输出</span></span>
<span class="line"><span class="token keyword">for</span> <span class="token for-or-select variable">user</span> <span class="token keyword">in</span> <span class="token variable"><span class="token variable">$(</span><span class="token function">cut</span> -d: <span class="token parameter variable">-f1</span> /etc/passwd<span class="token variable">)</span></span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;用户: <span class="token variable">$user</span>&quot;</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 带序列</span></span>
<span class="line"><span class="token keyword">for</span> <span class="token for-or-select variable">i</span> <span class="token keyword">in</span> <span class="token punctuation">{</span><span class="token number">1</span><span class="token punctuation">..</span><span class="token number">10</span><span class="token punctuation">}</span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token variable">$i</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"><span class="token keyword">for</span> <span class="token for-or-select variable">i</span> <span class="token keyword">in</span> <span class="token punctuation">{</span><span class="token number">1</span><span class="token punctuation">..</span><span class="token number">10</span><span class="token punctuation">..</span><span class="token number">2</span><span class="token punctuation">}</span><span class="token punctuation">;</span> <span class="token keyword">do</span>               <span class="token comment"># 步长为 2</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token variable">$i</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="while-循环" tabindex="-1"><a class="header-anchor" href="#while-循环"><span><code>while</code> 循环</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 基本语法</span></span>
<span class="line"><span class="token assign-left variable">i</span><span class="token operator">=</span><span class="token number">0</span></span>
<span class="line"><span class="token keyword">while</span> <span class="token punctuation">[</span> <span class="token variable">$i</span> <span class="token parameter variable">-lt</span> <span class="token number">10</span> <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token variable">$i</span></span>
<span class="line">    <span class="token assign-left variable">i</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$((</span>i <span class="token operator">+</span> <span class="token number">1</span><span class="token variable">))</span></span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 读取文件</span></span>
<span class="line"><span class="token keyword">while</span> <span class="token assign-left variable"><span class="token environment constant">IFS</span></span><span class="token operator">=</span> <span class="token builtin class-name">read</span> <span class="token parameter variable">-r</span> line<span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;行: <span class="token variable">$line</span>&quot;</span></span>
<span class="line"><span class="token keyword">done</span> <span class="token operator">&lt;</span> file.txt</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 读取 CSV</span></span>
<span class="line"><span class="token keyword">while</span> <span class="token assign-left variable"><span class="token environment constant">IFS</span></span><span class="token operator">=</span><span class="token string">&#39;,&#39;</span> <span class="token builtin class-name">read</span> <span class="token parameter variable">-r</span> col1 col2 col3<span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;列1: <span class="token variable">$col1</span>, 列2: <span class="token variable">$col2</span>, 列3: <span class="token variable">$col3</span>&quot;</span></span>
<span class="line"><span class="token keyword">done</span> <span class="token operator">&lt;</span> data.csv</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 无限循环</span></span>
<span class="line"><span class="token keyword">while</span> <span class="token boolean">true</span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;按 Ctrl+C 退出&quot;</span></span>
<span class="line">    <span class="token function">sleep</span> <span class="token number">1</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 监控命令输出</span></span>
<span class="line"><span class="token keyword">while</span> <span class="token operator">!</span> <span class="token function">ping</span> <span class="token parameter variable">-c</span> <span class="token number">1</span> google.com <span class="token operator">&amp;&gt;</span>/dev/null<span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;等待网络连接...&quot;</span></span>
<span class="line">    <span class="token function">sleep</span> <span class="token number">2</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;网络已连接&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="until-循环" tabindex="-1"><a class="header-anchor" href="#until-循环"><span><code>until</code> 循环</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 条件为真时退出（与 while 相反）</span></span>
<span class="line"><span class="token assign-left variable">i</span><span class="token operator">=</span><span class="token number">0</span></span>
<span class="line"><span class="token keyword">until</span> <span class="token punctuation">[</span> <span class="token variable">$i</span> <span class="token parameter variable">-ge</span> <span class="token number">10</span> <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token variable">$i</span></span>
<span class="line">    <span class="token assign-left variable">i</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$((</span>i <span class="token operator">+</span> <span class="token number">1</span><span class="token variable">))</span></span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 等待服务启动</span></span>
<span class="line"><span class="token keyword">until</span> systemctl is-active <span class="token parameter variable">--quiet</span> nginx<span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;等待 nginx 启动...&quot;</span></span>
<span class="line">    <span class="token function">sleep</span> <span class="token number">2</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;nginx 已启动&quot;</span></span>
<span class="line"></span></code></pre></div><h3 id="循环控制" tabindex="-1"><a class="header-anchor" href="#循环控制"><span>循环控制</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token builtin class-name">break</span>                               <span class="token comment"># 跳出循环</span></span>
<span class="line"><span class="token builtin class-name">break</span> n                             <span class="token comment"># 跳出 n 层循环</span></span>
<span class="line"><span class="token builtin class-name">continue</span>                            <span class="token comment"># 跳过当前迭代，继续下一次</span></span>
<span class="line"><span class="token builtin class-name">continue</span> n                          <span class="token comment"># 跳过 n 层循环的当前迭代</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 示例</span></span>
<span class="line"><span class="token keyword">for</span> <span class="token for-or-select variable">i</span> <span class="token keyword">in</span> <span class="token punctuation">{</span><span class="token number">1</span><span class="token punctuation">..</span><span class="token number">10</span><span class="token punctuation">}</span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token variable">$i</span> <span class="token parameter variable">-eq</span> <span class="token number">5</span> <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">        <span class="token builtin class-name">break</span>                       <span class="token comment"># i=5 时跳出循环</span></span>
<span class="line">    <span class="token keyword">fi</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token variable">$i</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">for</span> <span class="token for-or-select variable">i</span> <span class="token keyword">in</span> <span class="token punctuation">{</span><span class="token number">1</span><span class="token punctuation">..</span><span class="token number">10</span><span class="token punctuation">}</span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token variable">$i</span> <span class="token parameter variable">-eq</span> <span class="token number">5</span> <span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">        <span class="token builtin class-name">continue</span>                    <span class="token comment"># 跳过 i=5</span></span>
<span class="line">    <span class="token keyword">fi</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token variable">$i</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="六、函数" tabindex="-1"><a class="header-anchor" href="#六、函数"><span>六、函数</span></a></h2><h3 id="定义和调用" tabindex="-1"><a class="header-anchor" href="#定义和调用"><span>定义和调用</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 方式 1</span></span>
<span class="line"><span class="token keyword">function</span> <span class="token function-name function">name</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    commands</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 方式 2（推荐）</span></span>
<span class="line"><span class="token function-name function">name</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    commands</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 调用</span></span>
<span class="line">name</span>
<span class="line">name arg1 arg2</span>
<span class="line"></span></code></pre></div><h3 id="参数和返回值" tabindex="-1"><a class="header-anchor" href="#参数和返回值"><span>参数和返回值</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 函数参数</span></span>
<span class="line"><span class="token function-name function">greet</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token builtin class-name">local</span> <span class="token assign-left variable">name</span><span class="token operator">=</span><span class="token variable">$1</span></span>
<span class="line">    <span class="token builtin class-name">local</span> <span class="token assign-left variable">greeting</span><span class="token operator">=</span><span class="token variable">\${2<span class="token operator">:-</span>&quot;Hello&quot;}</span>     <span class="token comment"># 默认值</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;<span class="token variable">$greeting</span>, <span class="token variable">$name</span>!&quot;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">greet <span class="token string">&quot;John&quot;</span>                         <span class="token comment"># 输出：Hello, John!</span></span>
<span class="line">greet <span class="token string">&quot;John&quot;</span> <span class="token string">&quot;Hi&quot;</span>                    <span class="token comment"># 输出：Hi, John!</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 返回值（0-255）</span></span>
<span class="line"><span class="token function-name function">is_even</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token builtin class-name">local</span> <span class="token assign-left variable">num</span><span class="token operator">=</span><span class="token variable">$1</span></span>
<span class="line">    <span class="token builtin class-name">return</span> <span class="token variable"><span class="token variable">$((</span>num <span class="token operator">%</span> <span class="token number">2</span> <span class="token operator">==</span> <span class="token number">0</span> <span class="token operator">?</span> <span class="token number">0</span> <span class="token operator">:</span> <span class="token number">1</span><span class="token variable">))</span></span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">if</span> is_even <span class="token number">4</span><span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;4 是偶数&quot;</span></span>
<span class="line"><span class="token keyword">fi</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 获取输出（字符串返回）</span></span>
<span class="line"><span class="token function-name function">get_name</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;John Doe&quot;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token assign-left variable">name</span><span class="token operator">=</span><span class="token variable"><span class="token variable">$(</span>get_name<span class="token variable">)</span></span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token variable">$name</span>                           <span class="token comment"># 输出：John Doe</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="局部变量" tabindex="-1"><a class="header-anchor" href="#局部变量"><span>局部变量</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function-name function">myfunc</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token builtin class-name">local</span> <span class="token assign-left variable">local_var</span><span class="token operator">=</span><span class="token string">&quot;只能在函数内访问&quot;</span></span>
<span class="line">    <span class="token assign-left variable">global_var</span><span class="token operator">=</span><span class="token string">&quot;可以在任何地方访问&quot;</span>   <span class="token comment"># 不加 local 就是全局变量</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token variable">$local_var</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre></div><h3 id="函数库" tabindex="-1"><a class="header-anchor" href="#函数库"><span>函数库</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># utils.sh - 函数库文件</span></span>
<span class="line"><span class="token comment"># 包含于：source ./utils.sh</span></span>
<span class="line"></span>
<span class="line"><span class="token function-name function">log_info</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;[INFO] <span class="token variable"><span class="token variable">$(</span><span class="token function">date</span> <span class="token string">&#39;+%Y-%m-%d %H:%M:%S&#39;</span><span class="token variable">)</span></span> - <span class="token variable">$1</span>&quot;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token function-name function">log_error</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;[ERROR] <span class="token variable"><span class="token variable">$(</span><span class="token function">date</span> <span class="token string">&#39;+%Y-%m-%d %H:%M:%S&#39;</span><span class="token variable">)</span></span> - <span class="token variable">$1</span>&quot;</span> <span class="token operator">&gt;</span><span class="token file-descriptor important">&amp;2</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token function-name function">die</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    log_error <span class="token string">&quot;<span class="token variable">$1</span>&quot;</span></span>
<span class="line">    <span class="token builtin class-name">exit</span> <span class="token number">1</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 使用函数库</span></span>
<span class="line"><span class="token builtin class-name">source</span> ./utils.sh</span>
<span class="line">log_info <span class="token string">&quot;Script started&quot;</span></span>
<span class="line">log_error <span class="token string">&quot;Something went wrong&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="七、脚本调试" tabindex="-1"><a class="header-anchor" href="#七、脚本调试"><span>七、脚本调试</span></a></h2><h3 id="调试方法" tabindex="-1"><a class="header-anchor" href="#调试方法"><span>调试方法</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 1. 运行时调试</span></span>
<span class="line"><span class="token function">bash</span> <span class="token parameter variable">-x</span> script.sh                    <span class="token comment"># 显示每条命令的执行过程</span></span>
<span class="line"><span class="token function">bash</span> <span class="token parameter variable">-v</span> script.sh                    <span class="token comment"># 显示原始脚本内容</span></span>
<span class="line"><span class="token function">bash</span> <span class="token parameter variable">-n</span> script.sh                    <span class="token comment"># 语法检查（不执行）</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 2. 脚本内启用调试</span></span>
<span class="line"><span class="token comment">#!/bin/bash -x                       # 在 shebang 中启用</span></span>
<span class="line"><span class="token builtin class-name">set</span> <span class="token parameter variable">-x</span>                               <span class="token comment"># 启用调试</span></span>
<span class="line"><span class="token builtin class-name">set</span> +x                               <span class="token comment"># 关闭调试</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 3. 断点调试</span></span>
<span class="line"><span class="token builtin class-name">trap</span> <span class="token string">&#39;echo &quot;Line $LINENO: $BASH_COMMAND&quot;&#39;</span> DEBUG  <span class="token comment"># 每行执行前打印</span></span>
<span class="line"></span></code></pre></div><h3 id="常用调试技巧" tabindex="-1"><a class="header-anchor" href="#常用调试技巧"><span>常用调试技巧</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 严格模式</span></span>
<span class="line"><span class="token builtin class-name">set</span> <span class="token parameter variable">-e</span>                               <span class="token comment"># 遇到错误立即退出</span></span>
<span class="line"><span class="token builtin class-name">set</span> <span class="token parameter variable">-u</span>                               <span class="token comment"># 使用未定义变量时报错</span></span>
<span class="line"><span class="token builtin class-name">set</span> <span class="token parameter variable">-o</span> pipefail                      <span class="token comment"># 管道中任一命令失败则整体失败</span></span>
<span class="line"><span class="token builtin class-name">set</span> <span class="token parameter variable">-euo</span> pipefail                    <span class="token comment"># 严格模式（推荐在脚本开头使用）</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 检查变量</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;Variable: <span class="token variable">\${var@Q}</span>&quot;</span>            <span class="token comment"># 显示变量的引用形式</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;Variable: <span class="token variable">\${var@A}</span>&quot;</span>            <span class="token comment"># 显示变量的声明形式</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 打印调试信息</span></span>
<span class="line"><span class="token assign-left variable"><span class="token environment constant">PS4</span></span><span class="token operator">=</span><span class="token string">&#39;+ \${BASH_SOURCE}:\${LINENO}:\${FUNCNAME[0]:+\${FUNCNAME[0]}:}&#39;</span>  <span class="token comment"># 自定义调试前缀</span></span>
<span class="line"></span></code></pre></div><h3 id="错误处理" tabindex="-1"><a class="header-anchor" href="#错误处理"><span>错误处理</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 检查命令执行结果</span></span>
<span class="line"><span class="token keyword">if</span> <span class="token operator">!</span> <span class="token builtin class-name">command</span><span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;命令执行失败&quot;</span></span>
<span class="line">    <span class="token builtin class-name">exit</span> <span class="token number">1</span></span>
<span class="line"><span class="token keyword">fi</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 或使用逻辑运算符</span></span>
<span class="line"><span class="token builtin class-name">command</span> <span class="token operator">||</span> <span class="token punctuation">{</span> <span class="token builtin class-name">echo</span> <span class="token string">&quot;失败&quot;</span><span class="token punctuation">;</span> <span class="token builtin class-name">exit</span> <span class="token number">1</span><span class="token punctuation">;</span> <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 使用 trap 捕获错误</span></span>
<span class="line"><span class="token builtin class-name">trap</span> <span class="token string">&#39;echo &quot;Error on line $LINENO&quot;; exit 1&#39;</span> ERR</span>
<span class="line"><span class="token builtin class-name">trap</span> <span class="token string">&#39;echo &quot;Script interrupted&quot;; cleanup; exit&#39;</span> INT <span class="token environment constant">TERM</span></span>
<span class="line"><span class="token builtin class-name">trap</span> <span class="token string">&#39;echo &quot;Script exited&quot;; cleanup&#39;</span> EXIT</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 清理函数</span></span>
<span class="line"><span class="token function-name function">cleanup</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;清理临时文件...&quot;</span></span>
<span class="line">    <span class="token function">rm</span> <span class="token parameter variable">-rf</span> /tmp/temp_<span class="token variable">$$</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token builtin class-name">trap</span> cleanup EXIT</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="八、shell-脚本模板" tabindex="-1"><a class="header-anchor" href="#八、shell-脚本模板"><span>八、Shell 脚本模板</span></a></h2><h3 id="标准模板" tabindex="-1"><a class="header-anchor" href="#标准模板"><span>标准模板</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/usr/bin/env bash</span></span>
<span class="line"><span class="token comment"># -*- coding: utf-8 -*-</span></span>
<span class="line"><span class="token comment">#</span></span>
<span class="line"><span class="token comment"># 脚本名称: script.sh</span></span>
<span class="line"><span class="token comment"># 描述: 脚本功能的简要描述</span></span>
<span class="line"><span class="token comment"># 用法: ./script.sh [选项] [参数]</span></span>
<span class="line"><span class="token comment"># 作者: Your Name</span></span>
<span class="line"><span class="token comment"># 日期: 2026-07-15</span></span>
<span class="line"><span class="token comment"># 版本: 1.0.0</span></span>
<span class="line"></span>
<span class="line"><span class="token builtin class-name">set</span> <span class="token parameter variable">-euo</span> pipefail                    <span class="token comment"># 严格模式</span></span>
<span class="line"><span class="token assign-left variable"><span class="token environment constant">IFS</span></span><span class="token operator">=</span><span class="token string">$&#39;<span class="token entity" title="\\n">\\n</span><span class="token entity" title="\\t">\\t</span>&#39;</span>                          <span class="token comment"># 安全的分隔符（仅换行和制表符）</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 颜色定义</span></span>
<span class="line"><span class="token builtin class-name">readonly</span> <span class="token assign-left variable">RED</span><span class="token operator">=</span><span class="token string">&#39;\\033[0;31m&#39;</span></span>
<span class="line"><span class="token builtin class-name">readonly</span> <span class="token assign-left variable">GREEN</span><span class="token operator">=</span><span class="token string">&#39;\\033[0;32m&#39;</span></span>
<span class="line"><span class="token builtin class-name">readonly</span> <span class="token assign-left variable">YELLOW</span><span class="token operator">=</span><span class="token string">&#39;\\033[0;33m&#39;</span></span>
<span class="line"><span class="token builtin class-name">readonly</span> <span class="token assign-left variable">NC</span><span class="token operator">=</span><span class="token string">&#39;\\033[0m&#39;</span>               <span class="token comment"># No Color</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 日志函数</span></span>
<span class="line"><span class="token function-name function">log_info</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token parameter variable">-e</span> <span class="token string">&quot;<span class="token variable">\${GREEN}</span>[INFO]<span class="token variable">\${NC}</span> <span class="token variable"><span class="token variable">$(</span><span class="token function">date</span> <span class="token string">&#39;+%H:%M:%S&#39;</span><span class="token variable">)</span></span> - <span class="token variable">$*</span>&quot;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token function-name function">log_warn</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token parameter variable">-e</span> <span class="token string">&quot;<span class="token variable">\${YELLOW}</span>[WARN]<span class="token variable">\${NC}</span> <span class="token variable"><span class="token variable">$(</span><span class="token function">date</span> <span class="token string">&#39;+%H:%M:%S&#39;</span><span class="token variable">)</span></span> - <span class="token variable">$*</span>&quot;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token function-name function">log_error</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token parameter variable">-e</span> <span class="token string">&quot;<span class="token variable">\${RED}</span>[ERROR]<span class="token variable">\${NC}</span> <span class="token variable"><span class="token variable">$(</span><span class="token function">date</span> <span class="token string">&#39;+%H:%M:%S&#39;</span><span class="token variable">)</span></span> - <span class="token variable">$*</span>&quot;</span> <span class="token operator">&gt;</span><span class="token file-descriptor important">&amp;2</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 使用说明</span></span>
<span class="line"><span class="token function-name function">usage</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">cat</span> <span class="token operator">&lt;&lt;</span><span class="token string">EOF</span>
<span class="line">用法: <span class="token variable"><span class="token variable">$(</span><span class="token function">basename</span> <span class="token string">&quot;<span class="token variable">$0</span>&quot;</span><span class="token variable">)</span></span> [选项] [参数]</span>
<span class="line"></span>
<span class="line">选项:</span>
<span class="line">    -h, --help      显示此帮助信息</span>
<span class="line">    -v, --verbose   详细输出</span>
<span class="line">    -d, --debug     调试模式</span>
<span class="line"></span>
<span class="line">示例:</span>
<span class="line">    <span class="token variable"><span class="token variable">$(</span><span class="token function">basename</span> <span class="token string">&quot;<span class="token variable">$0</span>&quot;</span><span class="token variable">)</span></span> -v</span>
<span class="line">EOF</span></span>
<span class="line">    <span class="token builtin class-name">exit</span> <span class="token number">0</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 参数解析</span></span>
<span class="line"><span class="token function-name function">parse_args</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">while</span> <span class="token punctuation">[</span><span class="token punctuation">[</span> <span class="token variable">$#</span> <span class="token parameter variable">-gt</span> <span class="token number">0</span> <span class="token punctuation">]</span><span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">        <span class="token keyword">case</span> <span class="token variable">$1</span> <span class="token keyword">in</span></span>
<span class="line">            -h<span class="token operator">|</span>--help<span class="token punctuation">)</span></span>
<span class="line">                usage</span>
<span class="line">                <span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line">            -v<span class="token operator">|</span>--verbose<span class="token punctuation">)</span></span>
<span class="line">                <span class="token assign-left variable">VERBOSE</span><span class="token operator">=</span>true</span>
<span class="line">                <span class="token builtin class-name">shift</span></span>
<span class="line">                <span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line">            -d<span class="token operator">|</span>--debug<span class="token punctuation">)</span></span>
<span class="line">                <span class="token builtin class-name">set</span> <span class="token parameter variable">-x</span></span>
<span class="line">                <span class="token builtin class-name">shift</span></span>
<span class="line">                <span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line">            --<span class="token punctuation">)</span></span>
<span class="line">                <span class="token builtin class-name">shift</span></span>
<span class="line">                <span class="token builtin class-name">break</span></span>
<span class="line">                <span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line">            -*<span class="token punctuation">)</span></span>
<span class="line">                log_error <span class="token string">&quot;未知选项: <span class="token variable">$1</span>&quot;</span></span>
<span class="line">                usage</span>
<span class="line">                <span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line">            *<span class="token punctuation">)</span></span>
<span class="line">                <span class="token assign-left variable">args</span><span class="token operator">+=</span><span class="token punctuation">(</span><span class="token string">&quot;<span class="token variable">$1</span>&quot;</span><span class="token punctuation">)</span></span>
<span class="line">                <span class="token builtin class-name">shift</span></span>
<span class="line">                <span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">esac</span></span>
<span class="line">    <span class="token keyword">done</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 主函数</span></span>
<span class="line"><span class="token function-name function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token builtin class-name">local</span> <span class="token assign-left variable">args</span><span class="token operator">=</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token builtin class-name">local</span> <span class="token assign-left variable">VERBOSE</span><span class="token operator">=</span>false</span>
<span class="line"></span>
<span class="line">    parse_args <span class="token string">&quot;<span class="token variable">$@</span>&quot;</span></span>
<span class="line"></span>
<span class="line">    log_info <span class="token string">&quot;脚本开始执行&quot;</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment"># 主要逻辑</span></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">[</span><span class="token punctuation">[</span> <span class="token variable">\${<span class="token operator">#</span>args<span class="token punctuation">[</span>@<span class="token punctuation">]</span>}</span> <span class="token parameter variable">-gt</span> <span class="token number">0</span> <span class="token punctuation">]</span><span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token keyword">then</span></span>
<span class="line">        log_info <span class="token string">&quot;参数: <span class="token variable">\${args<span class="token punctuation">[</span>*<span class="token punctuation">]</span>}</span>&quot;</span></span>
<span class="line">    <span class="token keyword">fi</span></span>
<span class="line"></span>
<span class="line">    log_info <span class="token string">&quot;脚本执行完成&quot;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 执行主函数</span></span>
<span class="line">main <span class="token string">&quot;<span class="token variable">$@</span>&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="使用-getopts-解析选项" tabindex="-1"><a class="header-anchor" href="#使用-getopts-解析选项"><span>使用 <code>getopts</code> 解析选项</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token shebang important">#!/bin/bash</span></span>
<span class="line"></span>
<span class="line"><span class="token function-name function">usage</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token builtin class-name">echo</span> <span class="token string">&quot;用法: <span class="token variable">$0</span> [-h] [-v] [-o 输出文件] [输入文件]&quot;</span></span>
<span class="line">    <span class="token builtin class-name">exit</span> <span class="token number">0</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">while</span> <span class="token builtin class-name">getopts</span> <span class="token string">&quot;hvo:&quot;</span> opt<span class="token punctuation">;</span> <span class="token keyword">do</span></span>
<span class="line">    <span class="token keyword">case</span> <span class="token variable">$opt</span> <span class="token keyword">in</span></span>
<span class="line">        h<span class="token punctuation">)</span></span>
<span class="line">            usage</span>
<span class="line">            <span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token function">v</span><span class="token punctuation">)</span></span>
<span class="line">            <span class="token assign-left variable">VERBOSE</span><span class="token operator">=</span>true</span>
<span class="line">            <span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line">        o<span class="token punctuation">)</span></span>
<span class="line">            <span class="token assign-left variable">OUTPUT_FILE</span><span class="token operator">=</span><span class="token string">&quot;<span class="token variable">$OPTARG</span>&quot;</span></span>
<span class="line">            <span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token punctuation">\\</span>?<span class="token punctuation">)</span></span>
<span class="line">            <span class="token builtin class-name">echo</span> <span class="token string">&quot;无效选项&quot;</span></span>
<span class="line">            usage</span>
<span class="line">            <span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">esac</span></span>
<span class="line"><span class="token keyword">done</span></span>
<span class="line"></span>
<span class="line"><span class="token builtin class-name">shift</span> <span class="token variable"><span class="token variable">$((</span>OPTIND <span class="token operator">-</span> <span class="token number">1</span><span class="token variable">))</span></span>                <span class="token comment"># 移除已处理的选项</span></span>
<span class="line"><span class="token builtin class-name">echo</span> <span class="token string">&quot;剩余参数: <span class="token variable">$*</span>&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,73)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};